@app.post("/items")
async def create_item(request: Request) -> JSONResponse:
    payload = await request.json()
    name = payload.get("name")
    if not name:
        raise HTTPException(status_code=400, detail="Field 'name' is required")

    with apm_client.capture_span(
        "business.create_item",
        span_type="app",
        span_subtype="logic",
        span_action="create",
    ):
        execute_sql(
            "INSERT INTO items (name, created_at) VALUES (?, ?)",
            (name, time.time()),
            commit=True,
        )
        row = execute_sql(
            "SELECT id, name, created_at FROM items ORDER BY id DESC LIMIT 1",
            fetchone=True,
        )

    return JSONResponse(
        content={
            "id": row["id"],
            "name": row["name"],
            "created_at": row["created_at"],
        },
        status_code=201,
    )


